DB_PASSWORD=your_password
DB_PORT=5432
DB_MAX_CONNECTIONS=20
DB_MIN_CONNECTIONS=5
```

### 設定ファイル
```javascript
require('dotenv').config();
const { Pool } = require('pg');

const pool = new Pool({
  user: process.env.DB_USER,
  host: process.env.DB_HOST,
  database: process.env.DB_NAME,
  password: process.env.DB_PASSWORD,
  port: process.env.DB_PORT,

  max: parseInt(process.env.DB_MAX_CONNECTIONS) || 20,
  min: parseInt(process.env.DB_MIN_CONNECTIONS) || 5,
  idleTimeoutMillis: 30000,
  connectionTimeoutMillis: 2000,
});

module.exports = pool;
```

## 4. プールの使用方法

### 基本的なクエリ実行
```javascript
const pool = require('./db-pool');

async function getUsers() {
  try {
    const result = await pool.query('SELECT * FROM users');
    return result.rows;
  } catch (error) {
    console.error('クエリエラー:', error);
    throw error;
  }
}

// パラメータ化クエリ
async function getUserById(userId) {
  try {
    const result = await pool.query('SELECT * FROM users WHERE id = $1', [userId]);
    return result.rows[0];
  } catch (error) {
    console.error('クエリエラー:', error);
    throw error;
  }
}
```

### トランザクションの使用
```javascript
async function transferMoney(fromUserId, toUserId, amount) {
  const client = await pool.connect();

  try {
    await client.query('BEGIN');

    await client.query(
      'UPDATE accounts SET balance = balance - $1 WHERE user_id = $2',
      [amount, fromUserId]
    );

    await client.query(
      'UPDATE accounts SET balance = balance + $1 WHERE user_id = $2',
      [amount, toUserId]
    );

    await client.query('COMMIT');
    console.log('トランザクション完了');
  } catch (error) {
    await client.query('ROLLBACK');
    console.error('トランザクションエラー:', error);
    throw error;
  } finally {
    client.release(); // コネクションをプールに戻す
  }
}
```

## 5. 実用的な設定例

```javascript
const { Pool } = require('pg');

class Database {
  constructor() {
    this.pool = new Pool({
      user: process.env.DB_USER,
      host: process.env.DB_HOST,
      database: process.env.DB_NAME,
      password: process.env.DB_PASSWORD,
      port: process.env.DB_PORT,

      max: 20,
      min: 5,
      idleTimeoutMillis: 30000,
      connectionTimeoutMillis: 2000,

      // SSL設定（本番環境では推奨）
      ssl: process.env.NODE_ENV === 'production' ? { rejectUnauthorized: false } : false,
    });

    // プールイベントの監視
    this.pool.on('connect', (client) => {
      console.log('新しいクライアントが接続されました');
    });

    this.pool.on('error', (err) => {
      console.error('プールでエラーが発生しました:', err);
    });
  }

  async query(text, params) {
    const start = Date.now();
    try {
      const result = await this.pool.query(text, params);
      const duration = Date.now() - start;
      console.log('クエリ実行時間:', duration, 'ms');
      return result;
    } catch (error) {
      console.error('データベースクエリエラー:', error);
      throw error;
    }
  }

  async getClient() {
    return await this.pool.connect();
  }

  async close() {
    await this.pool.end();
    console.log('プールが閉じられました');
  }
}

module.exports = new Database();
```

## 6. Express.jsアプリケーションでの使用例

```javascript
const express = require('express');
const db = require('./database');

const app = express();

app.get('/users', async (req, res) => {
  try {
    const result = await db.query('SELECT * FROM users');
    res.json(result.rows);
  } catch (error) {
    res.status(500).json({ error: 'データベースエラー' });
  }
});

// アプリケーション終了時のクリーンアップ
process.on('SIGINT', async () => {
  console.log('アプリケーションを終了しています...');
  await db.close();
  process.exit(0);
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`サーバーがポート${PORT}で起動しました`);
});
```

## 7. プール設定のベストプラクティス

```javascript
const poolConfig = {
  // 本番環境での推奨設定
  max: Math.min(parseInt(process.env.DB_MAX_CONNECTIONS) || 20, 20),
  min: parseInt(process.env.DB_MIN_CONNECTIONS) || 2,

  // タイムアウト設定
  idleTimeoutMillis: 10000,        // 10秒でアイドル接続を切断
  connectionTimeoutMillis: 3000,   // 3秒で接続タイムアウト
  acquireTimeoutMillis: 60000,     // 60秒でプールからの取得タイムアウト

  // 接続の健全性チェック
  allowExitOnIdle: true,

  // 接続文字列での設定も可能
  // connectionString: process.env.DATABASE_URL,
};
```

この設定により、効率的で安全なPostgreSQLコネクションプールが構築できます。本番環境では適切な環境変数の設定と、エラーハンドリングの実装を忘れずに行ってください。

