normal_texts:
コールバック地獄をasync/awaitにリファクタリングする例をいくつか紹介します。

## 例1: 基本的なコールバック地獄

### Before (コールバック地獄)
```javascript
// コールバック地獄の例
function getData(callback) {
    setTimeout(() => {
        console.log('データを取得中...');
        callback(null, 'data1');
    }, 1000);
}

function processData(data, callback) {
    setTimeout(() => {
        console.log('データを処理中...');
        callback(null, data + '_processed');
    }, 1000);
}

function saveData(data, callback) {
    setTimeout(() => {
        console.log('データを保存中...');
        callback(null, data + '_saved');
    }, 1000);
}

// 使用例（コールバック地獄）
getData((err, data) => {
    if (err) throw err;
    processData(data, (err, processedData) => {
        if (err) throw err;
        saveData(processedData, (err, savedData) => {
            if (err) throw err;
            console.log('完了:', savedData);
        });
    });
});
```

### After (async/await)
```javascript
// Promise版の関数に変更
function getData() {
    return new Promise((resolve) => {
        setTimeout(() => {
            console.log('データを取得中...');
            resolve('data1');
        }, 1000);
    });
}

function processData(data) {
    return new Promise((resolve) => {
        setTimeout(() => {
            console.log('データを処理中...');
            resolve(data + '_processed');
        }, 1000);
    });
}

function saveData(data) {
    return new Promise((resolve) => {
        setTimeout(() => {
            console.log('データを保存中...');
            resolve(data + '_saved');
        }, 1000);
    });
}

// async/awaitを使用
async function main() {
    try {
        const data = await getData();
        const processedData = await processData(data);
        const savedData = await saveData(processedData);
        console.log('完了:', savedData);
    } catch (error) {
        console.error('エラー:', error);
    }
}

main();
```

## 例2: ファイル読み込みの例

### Before (コールバック地獄)
```javascript
const fs = require('fs');

// コールバック地獄
fs.readFile('file1.txt', 'utf8', (err, data1) => {
    if (err) throw err;
    fs.readFile('file2.txt', 'utf8', (err, data2) => {
        if (err) throw err;
        fs.readFile('file3.txt', 'utf8', (err, data3) => {
            if (err) throw err;
            const combined = data1 + data2 + data3;
            fs.writeFile('combined.txt', combined, (err) => {
                if (err) throw err;
                console.log('ファイルの結合が完了しました');
            });
        });
    });
});
```

### After (async/await)
```javascript
const fs = require('fs').promises;

async function combineFiles() {
    try {
        const data1 = await fs.readFile('file1.txt', 'utf8');
        const data2 = await fs.readFile('file2.txt', 'utf8');
        const data3 = await fs.readFile('file3.txt', 'utf8');

        const combined = data1 + data2 + data3;
        await fs.writeFile('combined.txt', combined);

        console.log('ファイルの結合が完了しました');
    } catch (error) {
        console.error('エラーが発生しました:', error);
    }
}

combineFiles();
```

## 例3: API呼び出しの例

### Before (コールバック地獄)
```javascript
// コールバック地獄
function getUserData(userId, callback) {
    fetch(`/api/users/${userId}`)
        .then(response => response.json())
        .then(user => {
            getUserPosts(user.id, (err, posts) => {
                if (err) return callback(err);
                getPostComments(posts[0].id, (err, comments) => {
                    if (err) return callback(err);
                    callback(null, { user, posts, comments });
                });
            });
        })
        .catch(callback);
}
```

### After (async/await)
```javascript
async function getUserData(userId) {
    try {
        const userResponse = await fetch(`/api/users/${userId}`);
        const user = await userResponse.json();

        const posts = await getUserPosts(user.id);
        const comments = await getPostComments(posts[0].id);

        return { user, posts, comments };
    } catch (error) {
        throw new Error(`ユーザーデータの取得に失敗: ${error.message}`);
    }
}

async function getUserPosts(userId) {
    const response = await fetch(`/api/users/${userId}/posts`);
    return await response.json();
}

async function getPostComments(postId) {
    const response = await fetch(`/api/posts/${postId}/comments`);
    return await response.json();
}

// 使用例
async function main() {
    try {
        const data = await getUserData(123);
        console.log('取得したデータ:', data);
    } catch (error) {
        console.error('エラー:', error.message);
    }
}
```

## 並列処理の場合

### Before (コールバック地獄)
```javascript
// 並列で実行したい場合の複雑な処理
let results = {};
let completed = 0;

getData1((err, data1) => {
    if (err) throw err;
    results.data1 = data1;
    completed++;
    if (completed === 3) processResults(results);
});

getData2((err, data2) => {
    if (err) throw err;
    results.data2 = data2;
    completed++;
    if (completed === 3) processResults(results);
});

getData3((err, data3) => {
    if (err) throw err;
    results.data3 = data3;
    completed++;
    if (completed === 3) processResults(results);
});
```

### After (async/await with Promise.all)
```javascript
async function getAllData() {
    try {
        // 並列実行
        const [data1, data2, data3] = await Promise.all([
            getData1(),
            getData2(),
            getData3()
        ]);

        const results = { data1, data2, data3 };
        return processResults(results);
    } catch (error) {
        console.error('データ取得エラー:', error);
        throw error;
    }
}

getAllData();
```

## async/awaitの利点

1. **可読性の向上**: コードが同期的に見える
2. **エラーハンドリングの簡素化**: try-catchで一元管理
3. **デバッグの容易さ**: スタックトレースが分かりやすい
4. **条件分岐やループの扱いやすさ**: 通常の制御構文が使える

async/awaitを使うことで、コールバック地獄を解消し、より読みやすく保守しやすいコードにリファクタリングできます。

コールバック地獄をasync/awaitにリファクタリングする方法を説明します。

## コールバック地獄の例

まず、典型的なコールバック地獄のコードを見てみましょう：

```javascript
// コールバック地獄の例
function fetchUserData(userId, callback) {
  getUserById(userId, (err, user) => {
    if (err) {
      callback(err, null);
      return;
    }

    getPostsByUserId(user.id, (err, posts) => {
      if (err) {
        callback(err, null);
        return;
      }

      getCommentsForPosts(posts, (err, comments) => {
        if (err) {
          callback(err, null);
          return;
        }

        getUserProfile(user.id, (err, profile) => {
          if (err) {
            callback(err, null);
            return;
          }

          callback(null, {
            user,
            posts,
            comments,
            profile
          });
        });
      });
    });
  });
}
```

## async/awaitへのリファクタリング

### ステップ1: コールバック関数をPromiseに変換

```javascript
// コールバック関数をPromiseに変換
function getUserById(userId) {
  return new Promise((resolve, reject) => {
    // 既存のコールバック関数をラップ
    originalGetUserById(userId, (err, user) => {
      if (err) reject(err);
      else resolve(user);
    });
  });
}

function getPostsByUserId(userId) {
  return new Promise((resolve, reject) => {
    originalGetPostsByUserId(userId, (err, posts) => {
      if (err) reject(err);
      else resolve(posts);
    });
  });
}

function getCommentsForPosts(posts) {
  return new Promise((resolve, reject) => {
    originalGetCommentsForPosts(posts, (err, comments) => {
      if (err) reject(err);
      else resolve(comments);
    });
  });
}

function getUserProfile(userId) {
  return new Promise((resolve, reject) => {
    originalGetUserProfile(userId, (err, profile) => {
      if (err) reject(err);
      else resolve(profile);
    });
  });
}
```

### ステップ2: async/awaitを使用してリファクタリング

```javascript
// async/awaitバージョン
async function fetchUserData(userId) {
  try {
    const user = await getUserById(userId);
    const posts = await getPostsByUserId(user.id);
    const comments = await getCommentsForPosts(posts);
    const profile = await getUserProfile(user.id);

    return {
      user,
      posts,
      comments,
      profile
    };
  } catch (error) {
    throw error;
  }
}
```

## さらなる最適化

### 並行処理の活用

```javascript
// 並行処理で最適化
async function fetchUserDataOptimized(userId) {
  try {
    const user = await getUserById(userId);

    // posts取得とprofile取得を並行実行
    const [posts, profile] = await Promise.all([
      getPostsByUserId(user.id),
      getUserProfile(user.id)
    ]);

    // commentsはpostsが必要なので後で実行
    const comments = await getCommentsForPosts(posts);

    return {
      user,
      posts,
      comments,
      profile
    };
  } catch (error) {
    throw error;
  }
}
```

### util.promisifyを使用した変換

Node.jsの場合、`util.promisify`を使ってより簡潔に変換できます：

```javascript
const { promisify } = require('util');

// 既存のコールバック関数をPromise化
const getUserById = promisify(originalGetUserById);
const getPostsByUserId = promisify(originalGetPostsByUserId);
const getCommentsForPosts = promisify(originalGetCommentsForPosts);
const getUserProfile = promisify(originalGetUserProfile);

// そのまま async/await で使用可能
async function fetchUserData(userId) {
  try {
    const user = await getUserById(userId);
    const posts = await getPostsByUserId(user.id);
    const comments = await getCommentsForPosts(posts);
    const profile = await getUserProfile(user.id);

    return { user, posts, comments, profile };
  } catch (error) {
    throw error;
  }
}
```

## 使用例

```javascript
// 使用方法
async function main() {
  try {
    const userData = await fetchUserData(123);
    console.log('ユーザーデータを取得しました:', userData);
  } catch (error) {
    console.error('エラーが発生しました:', error);
  }
}

main();
```

## メリット

1. **可読性の向上**: ネストが浅くなり、コードが読みやすくなります
2. **エラーハンドリングの簡素化**: try-catch文で一元的にエラー処理ができます
3. **デバッグの容易さ**: スタックトレースがより分かりやすくなります
4. **保守性の向上**: 修正や機能追加が簡単になります

このようにコールバック地獄をasync/awaitにリファクタリングすることで、より保守しやすく読みやすいコードに変換できます。

コールバック地獄をasync/awaitにリファクタリングする例をいくつか示します。

## 例1: ファイル操作のコールバック地獄

### Before（コールバック地獄）
```javascript
const fs = require('fs');

function processFiles(callback) {
    fs.readFile('file1.txt', 'utf8', (err, data1) => {
        if (err) {
            callback(err);
            return;
        }

        fs.readFile('file2.txt', 'utf8', (err, data2) => {
            if (err) {
                callback(err);
                return;
            }

            const combined = data1 + data2;

            fs.writeFile('output.txt', combined, (err) => {
                if (err) {
                    callback(err);
                    return;
                }

                fs.readFile('output.txt', 'utf8', (err, finalData) => {
                    if (err) {
                        callback(err);
                        return;
                    }
                    callback(null, finalData);
                });
            });
        });
    });
}
```

### After（async/await）
```javascript
const fs = require('fs').promises;

async function processFiles() {
    try {
        const data1 = await fs.readFile('file1.txt', 'utf8');
        const data2 = await fs.readFile('file2.txt', 'utf8');

        const combined = data1 + data2;

        await fs.writeFile('output.txt', combined);
        const finalData = await fs.readFile('output.txt', 'utf8');

        return finalData;
    } catch (error) {
        throw error;
    }
}
```

## 例2: API呼び出しのコールバック地獄

### Before（コールバック地獄）
```javascript
function fetchUserData(userId, callback) {
    fetch(`/api/users/${userId}`)
        .then(response => response.json())
        .then(user => {
            fetch(`/api/posts/${user.id}`)
                .then(response => response.json())
                .then(posts => {
                    fetch(`/api/comments/${posts[0].id}`)
                        .then(response => response.json())
                        .then(comments => {
                            callback(null, {
                                user: user,
                                posts: posts,
                                comments: comments
                            });
                        })
                        .catch(err => callback(err));
                })
                .catch(err => callback(err));
        })
        .catch(err => callback(err));
}
```

### After（async/await）
```javascript
async function fetchUserData(userId) {
    try {
        const userResponse = await fetch(`/api/users/${userId}`);
        const user = await userResponse.json();

        const postsResponse = await fetch(`/api/posts/${user.id}`);
        const posts = await postsResponse.json();

        const commentsResponse = await fetch(`/api/comments/${posts[0].id}`);
        const comments = await commentsResponse.json();

        return {
            user,
            posts,
            comments
        };
    } catch (error) {
        throw error;
    }
}
```

## 例3: データベース操作のコールバック地獄

### Before（コールバック地獄）
```javascript
function createUserWithProfile(userData, profileData, callback) {
    db.beginTransaction((err) => {
        if (err) {
            callback(err);
            return;
        }

        db.query('INSERT INTO users SET ?', userData, (err, result) => {
            if (err) {
                return db.rollback(() => {
                    callback(err);
                });
            }

            const userId = result.insertId;
            profileData.user_id = userId;

            db.query('INSERT INTO profiles SET ?', profileData, (err) => {
                if (err) {
                    return db.rollback(() => {
                        callback(err);
                    });
                }

                db.commit((err) => {
                    if (err) {
                        return db.rollback(() => {
                            callback(err);
                        });
                    }
                    callback(null, { userId, message: 'User created successfully' });
                });
            });
        });
    });
}
```

### After（async/await）
```javascript
async function createUserWithProfile(userData, profileData) {
    const connection = await db.getConnection();

    try {
        await connection.beginTransaction();

        const [result] = await connection.query('INSERT INTO users SET ?', userData);
        const userId = result.insertId;

        profileData.user_id = userId;
        await connection.query('INSERT INTO profiles SET ?', profileData);

        await connection.commit();

        return { userId, message: 'User created successfully' };
    } catch (error) {
        await connection.rollback();
        throw error;
    } finally {
        connection.release();
    }
}
```

## 並列処理も含めた例

### Before（コールバック地獄）
```javascript
function fetchAllData(callback) {
    let results = {};
    let completed = 0;
    let hasError = false;

    function checkComplete() {
        completed++;
        if (completed === 3 && !hasError) {
            callback(null, results);
        }
    }

    fetch('/api/users')
        .then(res => res.json())
        .then(data => {
            if (!hasError) {
                results.users = data;
                checkComplete();
            }
        })
        .catch(err => {
            if (!hasError) {
                hasError = true;
                callback(err);
            }
        });

    fetch('/api/posts')
        .then(res => res.json())
        .then(data => {
            if (!hasError) {
                results.posts = data;
                checkComplete();
            }
        })
        .catch(err => {
            if (!hasError) {
                hasError = true;
                callback(err);
            }
        });

    fetch('/api/categories')
        .then(res => res.json())
        .then(data => {
            if (!hasError) {
                results.categories = data;
                checkComplete();
            }
        })
        .catch(err => {
            if (!hasError) {
                hasError = true;
                callback(err);
            }
        });
}
```

### After（async/await）
```javascript
async function fetchAllData() {
    try {
        const [usersResponse, postsResponse, categoriesResponse] = await Promise.all([
            fetch('/api/users'),
            fetch('/api/posts'),
            fetch('/api/categories')
        ]);

        const [users, posts, categories] = await Promise.all([
            usersResponse.json(),
            postsResponse.json(),
            categoriesResponse.json()
        ]);

        return { users, posts, categories };
    } catch (error) {
        throw error;
    }
}
```

## 使用例

```javascript
// async/await版の使用
async function main() {
    try {
        const result = await fetchAllData();
        console.log('データ取得成功:', result);

        const userData = await processFiles();
        console.log('ファイル処理完了:', userData);

    } catch (error) {
        console.error('エラー発生:', error);
    }
}

main();
```

## リファクタリングのメリット

1. **可読性の向上**: コードが上から下へ順番に読める
2. **エラーハンドリングの簡素化**: try-catchで統一的に処理
3. **ネストの削除**: コールバック地獄の解消
4. **デバッグの容易さ**: スタックトレースが追いやすい
5. **保守性の向上**: コードの修正や拡張が簡単

async/awaitを使うことで、非同期処理を同期処理のように書けるため、コードがより理解しやすくなります。

