ReactのError Boundaryを実装します。以下に基本的な実装とより高機能な実装の両方を示します。

## 1. 基本的なError Boundary

```jsx
import React from 'react';

class ErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = { hasError: false, error: null, errorInfo: null };
  }

  static getDerivedStateFromError(error) {
    // エラーが発生したときにstateを更新
    return { hasError: true };
  }

  componentDidCatch(error, errorInfo) {
    // エラーログを記録
    console.error('Error Boundary caught an error:', error, errorInfo);

    this.setState({
      error: error,
      errorInfo: errorInfo
    });
  }

  render() {
    if (this.state.hasError) {
      // エラー時のフォールバックUI
      return (
        <div style={{ padding: '20px', textAlign: 'center' }}>
          <h2>何かエラーが発生しました</h2>
          <details style={{ whiteSpace: 'pre-wrap' }}>
            {this.state.error && this.state.error.toString()}
            <br />
            {this.state.errorInfo.componentStack}
          </details>
        </div>
      );
    }

    return this.props.children;
  }
}

export default ErrorBoundary;
```

## 2. より高機能なError Boundary

```jsx
import React from 'react';

class AdvancedErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      hasError: false,
      error: null,
      errorInfo: null,
      eventId: null,
    };
  }

  static getDerivedStateFromError(error) {
    return { hasError: true };
  }

  componentDidCatch(error, errorInfo) {
    console.error('Error Boundary caught an error:', error, errorInfo);

    // エラーログをサーバーに送信する例
    this.logErrorToService(error, errorInfo);

    this.setState({
      error: error,
      errorInfo: errorInfo,
      eventId: this.generateEventId()
    });
  }

  logErrorToService = (error, errorInfo) => {
    // 実際のエラー監視サービス（Sentry、LogRocket等）に送信
    if (typeof window !== 'undefined' && window.Sentry) {
      window.Sentry.captureException(error, {
        contexts: {
          react: {
            componentStack: errorInfo.componentStack
          }
        }
      });
    }
  };

  generateEventId = () => {
    return Math.random().toString(36).substr(2, 9);
  };

  handleRetry = () => {
    this.setState({
      hasError: false,
      error: null,
      errorInfo: null,
      eventId: null,
    });
  };

  render() {
    if (this.state.hasError) {
      // カスタムフォールバックUIがpropsで渡された場合
      if (this.props.fallback) {
        return this.props.fallback(
          this.state.error,
          this.state.errorInfo,
          this.handleRetry
        );
      }

      // デフォルトのエラーUI
      return (
        <div className="error-boundary">
          <div className="error-content">
            <h2>予期しないエラーが発生しました</h2>
            <p>申し訳ありません。アプリケーションでエラーが発生しました。</p>

            {this.state.eventId && (
              <p>エラーID: <code>{this.state.eventId}</code></p>
            )}

            <div className="error-actions">
              <button onClick={this.handleRetry} className="retry-button">
                再試行
              </button>
              <button 
                onClick={() => window.location.reload()} 
                className="reload-button"
              >
                ページを再読み込み
              </button>
            </div>

            {process.env.NODE_ENV === 'development' && (
              <details className="error-details">
                <summary>エラーの詳細（開発環境のみ）</summary>
                <pre>
                  {this.state.error && this.state.error.toString()}
                  <br />
                  {this.state.errorInfo.componentStack}
                </pre>
              </details>
            )}
          </div>
        </div>
      );
    }

    return this.props.children;
  }
}

export default AdvancedErrorBoundary;
```

## 3. 関数コンポーネント版（カスタムフック使用）

```jsx
import React, { useState, useEffect } from 'react';

// Error Boundaryは現在クラスコンポーネントでのみ実装可能ですが、
// カスタムフックでエラーハンドリングをサポートできます
export const useErrorHandler = () => {
  const [error, setError] = useState(null);

  useEffect(() => {
    if (error) {
      throw error;
    }
  }, [error]);

  return setError;
};

// HOC版のError Boundary
export const withErrorBoundary = (WrappedComponent, errorComponent) => {
  const WithErrorBoundaryComponent = (props) => (
    <AdvancedErrorBoundary fallback={errorComponent}>
      <WrappedComponent {...props} />
    </WrappedComponent>
  );

  WithErrorBoundaryComponent.displayName = 
    `withErrorBoundary(${WrappedComponent.displayName || WrappedComponent.name})`;

  return WithErrorBoundaryComponent;
};
