Nginxのリバースプロキシ設定について詳しく説明します。

## 基本的なリバースプロキシ設定

### 1. 単純な転送設定

```nginx
server {
    listen 80;
    server_name example.com;

    location / {
        proxy_pass http://127.0.0.1:3000;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
    }
}
```

### 2. よく使用されるproxy_set_headerの説明

```nginx
# クライアントのオリジナルホスト名を保持
proxy_set_header Host $host;

# クライアントの実際のIPアドレス
proxy_set_header X-Real-IP $remote_addr;

# プロキシチェーンを通じたIPアドレスのリスト
proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;

# オリジナルのプロトコル（http/https）
proxy_set_header X-Forwarded-Proto $scheme;

# WebSocketサポート用
proxy_set_header Upgrade $http_upgrade;
proxy_set_header Connection "upgrade";
```

## 高度な設定例

### 1. 複数のバックエンドサーバー（ロードバランシング）

```nginx
upstream backend {
    server 127.0.0.1:3000;
    server 127.0.0.1:3001;
    server 127.0.0.1:3002;
}

server {
    listen 80;
    server_name example.com;

    location / {
        proxy_pass http://backend;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
    }
}
```

### 2. パス別のプロキシ設定

```nginx
server {
    listen 80;
    server_name example.com;

    # API呼び出しは別のサーバーに転送
    location /api/ {
        proxy_pass http://api-server:8080/;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
    }

    # 静的コンテンツは別のサーバーに転送
    location /static/ {
        proxy_pass http://static-server:8081/;
    }

    # その他は主アプリケーションサーバーに転送
    location / {
        proxy_pass http://app-server:3000;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
    }
}
```

### 3. HTTPS対応の設定

```nginx
server {
    listen 443 ssl http2;
    server_name example.com;

    ssl_certificate /path/to/certificate.crt;
    ssl_certificate_key /path/to/private.key;

    location / {
        proxy_pass http://127.0.0.1:3000;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;

        # タイムアウト設定
        proxy_connect_timeout 60s;
        proxy_send_timeout 60s;
        proxy_read_timeout 60s;

        # バッファリング設定
        proxy_buffering on;
        proxy_buffer_size 4k;
        proxy_buffers 8 4k;
    }
}

# HTTPからHTTPSへのリダイレクト
server {
    listen 80;
    server_name example.com;
    return 301 https://$server_name$request_uri;
}
```

## パフォーマンス最適化の設定

### 1. キャッシュ設定

```nginx
# キャッシュパスの定義
proxy_cache_path /var/cache/nginx levels=1:2 keys_zone=my_cache:10m max_size=10g 
                 inactive=60m use_temp_path=off;

server {
    listen 80;
    server_name example.com;

    location / {
        proxy_pass http://127.0.0.1:3000;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;

        # キャッシュ設定
        proxy_cache my_cache;
        proxy_cache_valid 200 302 10m;
        proxy_cache_valid 404 1m;
        proxy_cache_use_stale error timeout invalid_header updating
                             http_500 http_502 http_503 http_504;
    }
}
```

### 2. WebSocket対応

```nginx
server {
    listen 80;
    server_name example.com;

    location /ws {
        proxy_pass http://127.0.0.1:3000;
        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection "upgrade";
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;

        # WebSocket用のタイムアウト設定
        proxy_read_timeout 86400;
    }
}
```

## 便利な設定オプション

### 1. エラーハンドリング

```nginx
location / {
    proxy_pass http://backend;
    proxy_next_upstream error timeout invalid_header http_500 http_502 http_503 http_504;
    proxy_next_upstream_tries 3;
    proxy_next_upstream_timeout 10s;
}
```

### 2. ヘルスチェック

```nginx
upstream backend {
    server 127.0.0.1:3000 max_fails=3 fail_timeout=30s;
    server 127.0.0.1:3001 max_fails=3 fail_timeout=30s backup;
}
```

この設定を参考に、あなたの環境に合わせてカスタマイズしてください。特定の用途について詳しく知りたい場合は、お気軽にお聞きください。

Nginxのリバースプロキシ設定について説明します。

## 基本的なリバースプロキシ設定

### 1. 単純なリバースプロキシ

```nginx
server {
    listen 80;
    server_name example.com;

    location / {
        proxy_pass http://127.0.0.1:3000;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
    }
}
```

### 2. より詳細な設定例

```nginx
upstream backend {
    server 127.0.0.1:3000;
    server 127.0.0.1:3001;
}

server {
    listen 80;
    server_name your-domain.com;

    # リバースプロキシの設定
    location / {
        proxy_pass http://backend;

        # 基本的なヘッダー設定
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_set_header X-Forwarded-Host $host;
        proxy_set_header X-Forwarded-Port $server_port;

        # タイムアウト設定
        proxy_connect_timeout 30s;
        proxy_send_timeout 60s;
        proxy_read_timeout 60s;

        # バッファリング設定
        proxy_buffering on;
        proxy_buffer_size 16k;
        proxy_buffers 32 16k;

        # リダイレクトの処理
        proxy_redirect off;
    }
}
```

## HTTPSでの設定

```nginx
server {
    listen 443 ssl http2;
    server_name example.com;

    ssl_certificate /path/to/certificate.crt;
    ssl_certificate_key /path/to/private.key;

    location / {
        proxy_pass http://127.0.0.1:3000;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto https;
        proxy_set_header X-Forwarded-Ssl on;
    }
}

# HTTPからHTTPSへのリダイレクト
server {
    listen 80;
    server_name example.com;
    return 301 https://$server_name$request_uri;
}
```

## パス別のプロキシ設定

```nginx
server {
    listen 80;
    server_name example.com;

    # APIリクエストを別のサーバーに転送
    location /api/ {
        proxy_pass http://127.0.0.1:8080/;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
    }

    # 静的ファイルを別のサーバーに転送
    location /static/ {
        proxy_pass http://127.0.0.1:8081/;
    }

    # デフォルトはメインアプリケーション
    location / {
        proxy_pass http://127.0.0.1:3000;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
    }
}
```

## ロードバランシング設定

```nginx
upstream app_servers {
    least_conn;
    server 127.0.0.1:3000 weight=3;
    server 127.0.0.1:3001 weight=2;
    server 127.0.0.1:3002 backup;
}

server {
    listen 80;
    server_name example.com;

    location / {
        proxy_pass http://app_servers;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;

        # ヘルスチェック
        proxy_next_upstream error timeout http_500 http_502 http_503;
    }
}
```

## WebSocket対応設定

```nginx
server {
    listen 80;
    server_name example.com;

    location / {
        proxy_pass http://127.0.0.1:3000;
        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection "upgrade";
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
    }
}
```

## 重要な設定項目の説明

### ヘッダー設定
- `proxy_set_header Host $host`: オリジナルのHostヘッダーを維持
- `proxy_set_header X-Real-IP $remote_addr`: 実際のクライアントIPを転送
- `proxy_set_header X-Forwarded-For`: プロキシチェーンのIPを記録
- `proxy_set_header X-Forwarded-Proto`: HTTPSの情報を転送

### タイムアウト設定
- `proxy_connect_timeout`: バックエンドへの接続タイムアウト
- `proxy_send_timeout`: リクエスト送信のタイムアウト
- `proxy_read_timeout`: レスポンス読み取りのタイムアウト

## 設定の適用

1. 設定ファイルを保存
2. 設定をテスト: `nginx -t`
3. Nginxを再起動: `systemctl restart nginx`

このような設定により、Nginxを効果的なリバースプロキシとして使用できます。具体的な要件に応じて設定を調整してください。

Nginxのリバースプロキシ設定について詳しく説明します。

## 基本的な設定

### 1. 基本構成
```nginx
server {
    listen 80;
    server_name example.com;

    location / {
        proxy_pass http://backend_server;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
    }
}
```

### 2. upstream設定（負荷分散）
```nginx
upstream backend_servers {
    server 192.168.1.10:3000;
    server 192.168.1.11:3000;
    server 192.168.1.12:3000;
}

server {
    listen 80;
    server_name example.com;

    location / {
        proxy_pass http://backend_servers;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
    }
}
```

## 詳細設定オプション

### 1. タイムアウト設定
```nginx
location / {
    proxy_pass http://backend;

    # 接続タイムアウト
    proxy_connect_timeout 30s;

    # 送信タイムアウト
    proxy_send_timeout 30s;

    # 受信タイムアウト
    proxy_read_timeout 30s;
}
```

### 2. バッファリング設定
```nginx
location / {
    proxy_pass http://backend;

    # バッファリングを有効化
    proxy_buffering on;

    # バッファサイズ
    proxy_buffer_size 4k;
    proxy_buffers 8 4k;

    # 大きなレスポンス用
    proxy_busy_buffers_size 8k;
}
```

### 3. SSL/HTTPS設定
```nginx
server {
    listen 443 ssl http2;
    server_name example.com;

    ssl_certificate /path/to/certificate.crt;
    ssl_certificate_key /path/to/private.key;

    location / {
        proxy_pass http://backend;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;

        # SSL関連ヘッダー
        proxy_set_header X-Forwarded-Ssl on;
    }
}
```

## 実用的な設定例

### 1. Node.js アプリケーション用
```nginx
upstream nodejs_backend {
    server 127.0.0.1:3000;
    keepalive 32;
}

server {
    listen 80;
    server_name myapp.com;

    location / {
        proxy_pass http://nodejs_backend;
        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection 'upgrade';
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_cache_bypass $http_upgrade;
    }
}
```

### 2. API Gateway設定
```nginx
upstream api_v1 {
    server 192.168.1.10:8000;
    server 192.168.1.11:8000;
}

upstream api_v2 {
    server 192.168.1.20:8000;
    server 192.168.1.21:8000;
}

server {
    listen 80;
    server_name api.example.com;

    # API v1
    location /v1/ {
        proxy_pass http://api_v1/;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
    }

    # API v2
    location /v2/ {
        proxy_pass http://api_v2/;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
    }
}
```

### 3. WebSocket対応設定
```nginx
map $http_upgrade $connection_upgrade {
    default upgrade;
    '' close;
}

server {
    listen 80;
    server_name websocket.example.com;

    location / {
        proxy_pass http://websocket_backend;
        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection $connection_upgrade;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;

        # WebSocket用タイムアウト設定
        proxy_read_timeout 86400;
    }
}
```

## 負荷分散方式

### 1. ラウンドロビン（デフォルト）
```nginx
upstream backend {
    server server1.example.com;
    server server2.example.com;
    server server3.example.com;
}
```

### 2. 重み付きラウンドロビン
```nginx
upstream backend {
    server server1.example.com weight=3;
    server server2.example.com weight=1;
    server server3.example.com weight=1;
}
```

### 3. IP Hash
```nginx
upstream backend {
    ip_hash;
    server server1.example.com;
    server server2.example.com;
    server server3.example.com;
}
```

### 4. Least Connections
```nginx
upstream backend {
    least_conn;
    server server1.example.com;
    server server2.example.com;
    server server3.example.com;
}
```

## ヘルスチェック設定

```nginx
upstream backend {
    server server1.example.com max_fails=3 fail_timeout=30s;
    server server2.example.com max_fails=3 fail_timeout=30s;
    server server3.example.com backup;  # バックアップサーバー
}
```

## キャッシュ設定

```nginx
# キャッシュディレクトリ設定
proxy_cache_path /var/cache/nginx levels=1:2 keys_zone=my_cache:10m max_size=10g 
                 inactive=60m use_temp_path=off;

server {
    listen 80;
    server_name example.com;

    location / {
        proxy_cache my_cache;
        proxy_cache_valid 200 302 10m;
        proxy_cache_valid 404 1m;
        proxy_cache_use_stale error timeout updating http_500 http_502 http_503 http_504;

        proxy_pass http://backend;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;

        add_header X-Cache-Status $upstream_cache_status;
    }
}
```

これらの設定を参考に、あなたの具体的な用途に応じてカスタマイズしてください。何か特定の設定について詳しく知りたいことがあれば、お気軽にお聞きください。

