Node.jsアプリのメモリリークを調査する方法について、段階的に説明します。

## 1. メモリリークの兆候を確認

```bash
# プロセスのメモリ使用量を監視
ps aux | grep node

# top/htopでリアルタイム監視
htop
```

## 2. Node.js内蔵ツールでの調査

### process.memoryUsage()を使用
```javascript
// メモリ使用量の定期的な監視
setInterval(() => {
  const memUsage = process.memoryUsage();
  console.log({
    rss: Math.round(memUsage.rss / 1024 / 1024) + ' MB',        // 物理メモリ
    heapTotal: Math.round(memUsage.heapTotal / 1024 / 1024) + ' MB', // ヒープ全体
    heapUsed: Math.round(memUsage.heapUsed / 1024 / 1024) + ' MB',   // 使用済みヒープ
    external: Math.round(memUsage.external / 1024 / 1024) + ' MB'   // 外部メモリ
  });
}, 5000);
```

### v8.getHeapStatistics()でより詳細な情報
```javascript
const v8 = require('v8');

function printHeapStats() {
  const stats = v8.getHeapStatistics();
  console.log({
    totalHeapSize: Math.round(stats.total_heap_size / 1024 / 1024) + ' MB',
    usedHeapSize: Math.round(stats.used_heap_size / 1024 / 1024) + ' MB',
    heapSizeLimit: Math.round(stats.heap_size_limit / 1024 / 1024) + ' MB'
  });
}
```

## 3. ヒープダンプの取得と分析

### ヒープダンプの取得
```javascript
const v8 = require('v8');
const fs = require('fs');

// ヒープダンプを生成
function generateHeapDump() {
  const filename = `heapdump-${Date.now()}.heapsnapshot`;
  const heapdump = v8.getHeapSnapshot();
  const fileStream = fs.createWriteStream(filename);
  heapdump.pipe(fileStream);
  console.log(`Heap dump saved to ${filename}`);
}

// メモリ使用量が閾値を超えた時に自動生成
setInterval(() => {
  const memUsage = process.memoryUsage();
  const heapUsedMB = memUsage.heapUsed / 1024 / 1024;

  if (heapUsedMB > 100) { // 100MB以上の場合
    generateHeapDump();
  }
}, 10000);
```

### Chrome DevToolsでの分析
1. Chrome DevToolsを開く
2. Memory タブを選択
3. 生成したheapsnapshotファイルをロード
4. オブジェクトの保持状況を分析

## 4. 専用ツールでの調査

### clinic.jsを使用
```bash
npm install -g clinic
clinic doctor -- node app.js
clinic flame -- node app.js
clinic bubbleprof -- node app.js
```

### heapdumpパッケージ
```bash
npm install heapdump
```
```javascript
const heapdump = require('heapdump');

// USR2シグナルでヒープダンプを生成
process.on('SIGUSR2', () => {
  heapdump.writeSnapshot((err, filename) => {
    console.log('Heap dump written to', filename);
  });
});
```

## 5. 一般的なメモリリークパターンの確認

### イベントリスナーのリーク
```javascript
// 悪い例：リスナーが蓄積される
function badExample() {
  setInterval(() => {
    process.on('exit', () => {
      console.log('Exit handler');
    });
  }, 1000);
}

// 良い例：適切にクリーンアップ
function goodExample() {
  const handler = () => console.log('Exit handler');
  process.on('exit', handler);

  // 必要に応じて削除
  // process.removeListener('exit', handler);
}
```

### クロージャーのリーク
```javascript
// 悪い例：不要な参照を保持
function createHandler() {
  const largeData = new Array(1000000).fill('data');

  return function handler() {
    // largeDataへの参照が残り続ける
    console.log('Handler called');
  };
}

// 良い例：必要な分のみ保持
function createHandlerGood() {
  const largeData = new Array(1000000).fill('data');
  const neededData = largeData.slice(0, 10); // 必要分のみ

  return function handler() {
    console.log('Handler called', neededData.length);
  };
}
```

## 6. 監視とアラート設定

```javascript
// メモリ監視とアラート
class MemoryMonitor {
  constructor(threshold = 500) { // MB
    this.threshold = threshold;
    this.monitorInterval = null;
  }

  start() {
    this.monitorInterval = setInterval(() => {
      const memUsage = process.memoryUsage();
      const heapUsedMB = memUsage.heapUsed / 1024 / 1024;

      if (heapUsedMB > this.threshold) {
        console.error(`Memory leak detected! Heap usage: ${heapUsedMB.toFixed(2)} MB`);
        this.generateDump();
      }
    }, 30000); // 30秒ごと
  }

  stop() {
    if (this.monitorInterval) {
      clearInterval(this.monitorInterval);
    }
  }

  generateDump() {
    // ヒープダンプ生成処理
  }
}

const monitor = new MemoryMonitor(200);
monitor.start();
```

## 7. プロダクション環境での対策

```javascript
// Graceful shutdownでのメモリ監視
process.on('SIGTERM', () => {
  console.log('Received SIGTERM, performing graceful shutdown');

  // メモリ状況をログ出力
  const memUsage = process.memoryUsage();
  console.log('Final memory usage:', memUsage);

  // クリーンアップ処理
  cleanup();
  process.exit(0);
});

function cleanup() {
  // タイマーの停止
  // イベントリスナーの削除
  // データベース接続のクローズ
}
```

これらの方法を組み合わせることで、効果的にメモリリークを調査・特定できます。特にヒープダンプの分析が最も有効な手段となることが多いです。

Node.jsアプリのメモリリークを調査する方法をご説明します。

## 1. 基本的なメモリ使用量の監視

### プロセス情報の取得
```javascript
// メモリ使用量を定期的に監視
function logMemoryUsage() {
  const usage = process.memoryUsage();
  console.log({
    rss: `${Math.round(usage.rss / 1024 / 1024)} MB`,      // 物理メモリ使用量
    heapTotal: `${Math.round(usage.heapTotal / 1024 / 1024)} MB`,
    heapUsed: `${Math.round(usage.heapUsed / 1024 / 1024)} MB`,
    external: `${Math.round(usage.external / 1024 / 1024)} MB`
  });
}

// 10秒ごとに監視
setInterval(logMemoryUsage, 10000);
```

## 2. プロファイリングツールの使用

### Node.js組み込み機能
```bash
# ヒープスナップショットを生成
node --inspect your-app.js
```

### Chrome DevToolsでの調査
1. Chrome で `chrome://inspect` にアクセス
2. "Open dedicated DevTools for Node" をクリック
3. Memory タブでヒープスナップショットを取得

## 3. ライブラリを使った詳細調査

### memwatch-nextの使用
```javascript
const memwatch = require('memwatch-next');

// メモリリーク検出
memwatch.on('leak', (info) => {
  console.log('Memory leak detected:', info);
});

// ガベージコレクション統計
memwatch.on('stats', (stats) => {
  console.log('GC Stats:', {
    usage_trend: stats.usage_trend,
    estimated_base: stats.estimated_base,
    current_base: stats.current_base
  });
});

// ヒープ差分の取得
const hd = new memwatch.HeapDiff();
// 何らかの処理を実行
setTimeout(() => {
  const diff = hd.end();
  console.log('Heap diff:', diff);
}, 5000);
```

### heapdumpでのスナップショット
```javascript
const heapdump = require('heapdump');

// 手動でヒープダンプを作成
heapdump.writeSnapshot((err, filename) => {
  console.log('Heap dump written to:', filename);
});

// SIGUSRシグナルでダンプ作成を有効化
process.kill(process.pid, 'SIGUSR2');
```

## 4. よくあるメモリリークのパターンと対策

### イベントリスナーの削除忘れ
```javascript
// 悪い例
function setupListener() {
  const emitter = new EventEmitter();
  emitter.on('data', (data) => {
    // 処理
  });
  return emitter;
}

// 良い例
function setupListener() {
  const emitter = new EventEmitter();
  const handler = (data) => {
    // 処理
  };

  emitter.on('data', handler);

  // クリーンアップ関数を返す
  return {
    emitter,
    cleanup: () => emitter.removeListener('data', handler)
  };
}
```

### クロージャによる循環参照
```javascript
// 悪い例
function createHandler() {
  const largeData = new Array(1000000).fill('data');

  return function handler() {
    // largeDataへの参照が残り続ける
    console.log('Handler called');
  };
}

// 良い例
function createHandler() {
  return function handler() {
    console.log('Handler called');
    // 必要なデータのみを使用
  };
}
```

### タイマーの未クリア
```javascript
// 悪い例
function startProcess() {
  const timer = setInterval(() => {
    // 処理
  }, 1000);
  // clearInterval(timer) の呼び忘れ
}

// 良い例
function startProcess() {
  const timer = setInterval(() => {
    // 処理
  }, 1000);

  // プロセス終了時にタイマーをクリア
  process.on('SIGTERM', () => {
    clearInterval(timer);
  });

  return () => clearInterval(timer);
}
```

## 5. 自動化された監視

### 監視用のミドルウェア作成
```javascript
class MemoryMonitor {
  constructor(options = {}) {
    this.threshold = options.threshold || 100; // MB
    this.interval = options.interval || 30000; // 30秒
    this.alerts = [];
  }

  start() {
    this.timer = setInterval(() => {
      const usage = process.memoryUsage();
      const heapUsedMB = usage.heapUsed / 1024 / 1024;

      if (heapUsedMB > this.threshold) {
        this.sendAlert({
          timestamp: new Date(),
          heapUsed: heapUsedMB,
          threshold: this.threshold
        });
      }
    }, this.interval);
  }

  sendAlert(data) {
    console.warn('Memory usage alert:', data);
    // 必要に応じて外部サービスに通知
  }

  stop() {
    if (this.timer) {
      clearInterval(this.timer);
    }
  }
}

// 使用例
const monitor = new MemoryMonitor({ threshold: 150 });
monitor.start();
```

## 6. プロダクション環境での調査

### pm2での監視
```bash
# pm2でメモリ監視付きで起動
pm2 start app.js --max-memory-restart 300M

# メモリ使用量を確認
pm2 monit
```

### 本番環境でのヒープダンプ
```javascript
// 高メモリ使用時に自動ダンプ
const heapdump = require('heapdump');

function checkMemoryAndDump() {
  const usage = process.memoryUsage();
