## 4. よくあるメモリリークのパターンと対策

### イベントリスナーの解除忘れ
```javascript
// 悪い例
function badExample() {
  const emitter = new EventEmitter();
  emitter.on('data', handleData);
  // リスナーが解除されない
}

// 良い例
function goodExample() {
  const emitter = new EventEmitter();
  const handler = handleData;
  emitter.on('data', handler);

  // クリーンアップ
  return () => {
    emitter.removeListener('data', handler);
  };
}
```

### タイマーの解除忘れ
```javascript
// 悪い例
function badTimer() {
  setInterval(() => {
    // 何らかの処理
  }, 1000);
  // タイマーがクリアされない
}

