    // 何らかの処理
  }, 1000);

  return () => {
    clearInterval(timer);
  };
}
```

### グローバル変数への参照蓄積
```javascript
// 悪い例
let globalCache = [];

function addToCache(data) {
  globalCache.push(data); // 無限に蓄積される
}

// 良い例
class LRUCache {
  constructor(maxSize = 100) {
    this.maxSize = maxSize;
    this.cache = new Map();
  }

  set(key, value) {
    if (this.cache.size >= this.maxSize) {
      const firstKey = this.cache.keys().next().value;
      this.cache.delete(firstKey);
    }
    this.cache.set(key, value);
  }
}
```

## 5. 実践的なデバッグ手順

```javascript
// デバッグ用のメモリ監視クラス
class MemoryMonitor {
  constructor(interval = 30000) {
    this.interval = interval;
    this.baseline = process.memoryUsage();
    this.samples = [];
  }

  start() {
    this.timer = setInterval(() => {
      const usage = process.memoryUsage();
      const sample = {
        timestamp: Date.now(),
        rss: usage.rss,
        heapUsed: usage.heapUsed,
        heapTotal: usage.heapTotal,
        external: usage.external
      };

      this.samples.push(sample);

      // 直近10サンプルで増加傾向をチェック
      if (this.samples.length >= 10) {
        const recent = this.samples.slice(-10);
        const trend = this.calculateTrend(recent);

        if (trend.heapUsed > 5) { // 5MB/sample以上の増加
          console.warn('Potential memory leak detected!', trend);
        }

        // 古いサンプルを削除（メモリ使用量を抑制）
        if (this.samples.length > 100) {
          this.samples = this.samples.slice(-50);
        }
      }

      this.logMemoryUsage(usage);
    }, this.interval);
  }

  stop() {
    if (this.timer) {
      clearInterval(this.timer);
    }
  }

  calculateTrend(samples) {
    const first = samples[0];
    const last = samples[samples.length - 1];

    return {
      heapUsed: (last.heapUsed - first.heapUsed) / 1024 / 1024 / samples.length,
      rss: (last.rss - first.rss) / 1024 / 1024 / samples.length
    };
  }

  logMemoryUsage(usage) {
    console.log(`Memory Usage: RSS=${Math.round(usage.rss/1024/1024)}MB, ` +
                `Heap=${Math.round(usage.heapUsed/1024/1024)}MB`);
  }

  generateReport() {
    return {
      totalSamples: this.samples.length,
      currentUsage: process.memoryUsage(),
      baseline: this.baseline,
      samples: this.samples
    };
  }
}

// 使用例
const monitor = new MemoryMonitor(5000); // 5秒間隔
monitor.start();

// アプリケーション終了時
process.on('SIGTERM', () => {
  monitor.stop();
  console.log('Memory Report:', JSON.stringify(monitor.generateReport(), null, 2));
});
```

## 6. 予防策

```javascript
// リソース管理の基本パターン
class ResourceManager {
  constructor() {
    this.resources = new Set();
  }

  addResource(resource) {
    this.resources.add(resource);
    return resource;
  }

  removeResource(resource) {
    if (typeof resource.cleanup === 'function') {
      resource.cleanup();
    }
    this.resources.delete(resource);
  }

  cleanup() {
    for (const resource of this.resources) {
      this.removeResource(resource);
    }
  }
}

// 使用例
const resourceManager = new ResourceManager();

process.on('exit', () => {
  resourceManager.cleanup();
});
```

これらの方法を組み合わせて、段階的にメモリリークの原因を特定し、修正していくことをお勧めします。

