## 1. Token Bucket（トークンバケット）アルゴリズム

最も一般的で推奨される方法です。

```python
import time
import threading

class TokenBucket:
    def __init__(self, capacity, refill_rate):
        self.capacity = capacity      # バケットの容量
        self.tokens = capacity        # 現在のトークン数
        self.refill_rate = refill_rate  # 毎秒のトークン補充率
        self.last_refill = time.time()
        self.lock = threading.Lock()

    def consume(self, tokens=1):
        with self.lock:
            now = time.time()
            # 経過時間分のトークンを補充
            elapsed = now - self.last_refill
            self.tokens = min(self.capacity, 
                             self.tokens + elapsed * self.refill_rate)
            self.last_refill = now

            if self.tokens >= tokens:
                self.tokens -= tokens
                return True
            return False

# 使用例
bucket = TokenBucket(capacity=10, refill_rate=1)  # 10リクエスト/秒
if bucket.consume():
    # リクエスト処理
    print("リクエスト許可")
else:
    print("レート制限に達しました")
```

## 2. Sliding Window Log

```python
import time
from collections import deque

class SlidingWindowLog:
    def __init__(self, limit, window_size):
        self.limit = limit
        self.window_size = window_size
        self.requests = deque()

    def is_allowed(self):
        now = time.time()
        # 古いリクエストを削除
        while self.requests and self.requests[0] <= now - self.window_size:
            self.requests.popleft()

        if len(self.requests) < self.limit:
            self.requests.append(now)
            return True
        return False

# 使用例
limiter = SlidingWindowLog(limit=100, window_size=60)  # 100リクエスト/分
```

## 3. Flask での実装例

```python
from flask import Flask, request, jsonify
from functools import wraps
import redis
import time

app = Flask(__name__)
redis_client = redis.Redis(host='localhost', port=6379, db=0)

def rate_limit(max_requests=100, window=60):
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            # クライアントの識別（IPアドレスまたはAPIキー）
            client_id = request.remote_addr
            key = f"rate_limit:{client_id}"

            current_time = int(time.time())
            window_start = current_time - window

            # 現在のウィンドウ内のリクエスト数を取得
            pipe = redis_client.pipeline()
            pipe.zremrangebyscore(key, 0, window_start)  # 古いエントリを削除
            pipe.zadd(key, {str(current_time): current_time})  # 現在のリクエストを追加
            pipe.zcard(key)  # 現在のリクエスト数を取得
            pipe.expire(key, window)  # TTL設定
            results = pipe.execute()

            request_count = results[2]

            if request_count > max_requests:
                return jsonify({
                    'error': 'Rate limit exceeded',
                    'retry_after': window
                }), 429

            return f(*args, **kwargs)
        return decorated_function
    return decorator

@app.route('/api/data')
@rate_limit(max_requests=10, window=60)  # 10リクエスト/分
def get_data():
    return jsonify({'data': 'Hello World'})
```

