## Token Bucket
```javascript
class TokenBucket {
  constructor(capacity, refillRate) {
    this.capacity = capacity;
    this.tokens = capacity;
    this.refillRate = refillRate;
    this.lastRefill = Date.now();
  }

  consume() {
    this.refill();
    if (this.tokens >= 1) {
      this.tokens--;
      return true;
    }
    return false;
  }

  refill() {
    const now = Date.now();
    const tokensToAdd = (now - this.lastRefill) / 1000 * this.refillRate;
    this.tokens = Math.min(this.capacity, this.tokens + tokensToAdd);
    this.lastRefill = now;
  }
}
```

## Sliding Window
```javascript
const slidingWindow = new Map();

function isAllowed(userId, limit, windowMs) {
  const now = Date.now();
  const userRequests = slidingWindow.get(userId) || [];

  // 古いリクエスト削除
  const validRequests = userRequests.filter(time => now - time < windowMs);

  if (validRequests.length < limit) {
    validRequests.push(now);
    slidingWindow.set(userId, validRequests);
    return true;
  }
  return false;
}
```

## Express middleware
```javascript
const rateLimit = (windowMs, max) => {
  const clients = new Map();

  return (req, res, next) => {
    const ip = req.ip;
    const now = Date.now();

    if (!clients.has(ip)) {
      clients.set(ip, { count: 1, resetTime: now + windowMs });
      return next();
    }

    const client = clients.get(ip);

    if (now > client.resetTime) {
      client.count = 1;
      client.resetTime = now + windowMs;
      return next();
    }

    if (client.count >= max) {
      return res.status(429).json({ error: 'Too Many Requests' });
    }

    client.count++;
    next();
  };
};
```

Redis使う場合 → `INCR key` + `EXPIRE`。分散環境対応。

選択: トラフィック パターンで決める。バースト許可 → Token Bucket。一定制限 → Fixed Window。
